const items = $input.all();
const lembretes = items.filter(l => l.json.reminder_id);

if (lembretes.length === 0) {
  return [];
}

return lembretes.map(l => {
  const d = l.json;
  let message = d.mensagem;

  if (!message) {
    const date = d.data_consulta ? new Date(d.data_consulta).toLocaleDateString('pt-BR') : '';
    const time = d.hora_consulta ? d.hora_consulta.substring(0,5) : '';
    const dentist = d.nome_dentista || '';

    switch (d.tipo) {
      case 'consulta_24h':
        message = `Olá ${d.nome_paciente}! 😊 Lembramos que você tem consulta amanhã (${date}) às ${time} com Dr(a). ${dentist} no consultório da Dra. Andreia. Confirme sua presença respondendo SIM. Para cancelar ou reagendar, fale conosco!`;
        break;
      case 'consulta_1h':
        message = `${d.nome_paciente}, sua consulta é em 1 hora! ⏰ Às ${time} com Dr(a). ${dentist}. Estamos esperando você! 😊`;
        break;
      case 'retorno':
        message = `Olá ${d.nome_paciente}! 🦷 Está na hora do seu retorno. Agende sua consulta conosco pelo WhatsApp!`;
        break;
      default:
        message = `Olá ${d.nome_paciente}! 😊 Você tem um lembrete do consultório da Dra. Andreia. Entre em contato para mais informações.`;
    }
  }

  return { json: { reminder_id: d.reminder_id, phone: d.telefone_paciente, message } };
});
